import base64
import pickle
import logging
from typing import Optional, Dict, Any

# Configure logging
logger = logging.getLogger(__name__)


def load_preferences_from_cookie(encoded_prefs: str) -> Dict[str, Any]:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences.
                      Can be standard or URL-safe base64 encoding.

    Returns:
        A dictionary containing the user's preference settings.
        Returns empty dict if input is invalid, malformed, or contains unsafe data.

    Security Note:
        Uses restricted unpickling to prevent code execution attacks.
        Only allows basic Python types (dict, list, tuple, str, int, float, bool, None).
    """
    if not encoded_prefs or not isinstance(encoded_prefs, str):
        return {}

    try:
        # Handle URL-safe base64 encoding (common in cookies)
        # Replace URL-safe characters back to standard base64
        encoded_prefs = encoded_prefs.replace('-', '+').replace('_', '/')

        # Add padding if needed
        padding_needed = 4 - (len(encoded_prefs) % 4)
        if padding_needed != 4:
            encoded_prefs += '=' * padding_needed

        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Create a custom unpickler with restricted classes for security
        class RestrictedUnpickler(pickle.Unpickler):
            """Custom unpickler that only allows safe Python types."""
            SAFE_CLASSES = {
                'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool',
                'NoneType', 'OrderedDict', 'datetime', 'date'
            }

            def find_class(self, module, name):
                # Only allow basic types from builtins and common modules
                if module == "builtins" and name in self.SAFE_CLASSES:
                    return super().find_class(module, name)
                elif module == "collections" and name == "OrderedDict":
                    return super().find_class(module, name)
                elif module == "datetime" and name in ("datetime", "date"):
                    return super().find_class(module, name)
                # Reject any other classes
                raise pickle.UnpicklingError(
                    f"Forbidden class: {module}.{name}"
                )

        # Deserialize using the restricted unpickler
        import io
        preferences = RestrictedUnpickler(io.BytesIO(decoded_data)).load()

        # Ensure the result is a dictionary
        if not isinstance(preferences, dict):
            logger.warning(
                "Unpickled object is not a dictionary, got %s",
                type(preferences).__name__
            )
            return {}

        return preferences

    except (base64.binascii.Error, UnicodeDecodeError) as e:
        logger.warning("Base64 decoding failed: %s", str(e))
        return {}
    except pickle.UnpicklingError as e:
        logger.warning("Unpickling failed: %s", str(e))
        return {}
    except (EOFError, ImportError, AttributeError, IndexError) as e:
        # These can occur with malformed pickle data
        logger.warning("Malformed pickle data: %s", str(e))
        return {}
    except Exception as e:
        # Catch-all for any other unexpected errors
        logger.error("Unexpected error loading preferences: %s", str(e))
        return {}

