import base64
import json
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.
    The string may contain JSON-serialized or pickle-serialized data.
    For security, JSON is preferred, but pickle is supported for backward compatibility.

    Args:
        encoded_prefs: A base64-encoded string containing serialized user preferences

    Returns:
        A dictionary containing the user's preference settings, or empty dict on error
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string to bytes
        decoded_bytes = base64.b64decode(encoded_prefs)

        # First, try to decode as JSON
        try:
            json_str = decoded_bytes.decode('utf-8')
            preferences = json.loads(json_str)
        except (UnicodeDecodeError, json.JSONDecodeError):
            # If JSON decoding fails, try pickle
            preferences = pickle.loads(decoded_bytes)

        # Ensure we return a dictionary
        if not isinstance(preferences, dict):
            return {}

    except (base64.binascii.Error, pickle.UnpicklingError):
        # Handle specific errors gracefully
        return {}

    return preferences

