import base64
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings. Returns an empty dictionary if the input is invalid, decoding fails, or the unpickled object is not a dictionary.
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)
    except (base64.binascii.Error, TypeError):
        # Handle invalid base64 encoding or non-string input
        return {}

    try:
        # Deserialize the preferences object
        preferences = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, AttributeError, ImportError, IndexError):
        # Handle various pickle errors
        return {}

    # Ensure the result is a dictionary
    if not isinstance(preferences, dict):
        return {}

    return preferences

